
<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><title>{{ $contract->contract_number }}</title><style>body{font-family:Arial,sans-serif;max-width:900px;margin:40px auto;color:#172033}dl{display:grid;grid-template-columns:220px 1fr;gap:10px}pre{white-space:pre-wrap;background:#f4f4f5;padding:16px}@media print{button{display:none}}</style></head><body><button onclick="window.print()">Imprimer</button><h1>Contrat de location {{ $contract->contract_number }}</h1><p>Version {{ $contract->currentVersion?->version_number }} — empreinte {{ $contract->currentVersion?->content_hash }}</p><dl><dt>Client</dt><dd>{{ $contract->customer->displayName() }}</dd><dt>Véhicule</dt><dd>{{ $contract->vehicle->registration_number }} — {{ $contract->vehicle->brand }} {{ $contract->vehicle->model }}</dd><dt>Période</dt><dd>{{ $contract->expected_start_at->format('d/m/Y H:i') }} au {{ $contract->expected_return_at->format('d/m/Y H:i') }}</dd><dt>Montant location</dt><dd>{{ $contract->rental_subtotal }} {{ $contract->currency }}</dd><dt>Caution requise</dt><dd>{{ $contract->deposit_required }} {{ $contract->currency }}</dd></dl><h2>Conditions versionnées</h2><pre>{{ json_encode($contract->currentVersion?->terms_snapshot, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE) }}</pre><h2>Acceptation</h2>@forelse($contract->acceptances as $acceptance)<p>Accepté par {{ $acceptance->accepted_by_name }} le {{ $acceptance->accepted_at->format('d/m/Y H:i') }} via {{ $acceptance->acceptance_method->value }}.</p>@empty<p>Contrat non accepté.</p>@endforelse</body></html>

